#!/usr/bin/env node

import { promises as fs } from 'node:fs';
import path from 'node:path';
import process from 'node:process';

const usage = `Usage:
  node scripts/concat-sections.mjs [options]

Options:
  --sections-dir <dir>       Sections directory to read. Default: sections
  --output <file>            Write concatenated markdown to a file. Default: stdout
  --no-toc                   Omit the generated file list.
  --no-boundaries            Omit per-file BEGIN/END comments.
  --exclude-usage-examples   Skip sections/12-usage-examples.
  --help                     Show this help.
`;

function parseArgs(argv) {
  const opts = {
    sectionsDir: 'sections',
    output: null,
    toc: true,
    boundaries: true,
    excludeUsageExamples: false,
  };

  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === '--help' || arg === '-h') {
      opts.help = true;
    } else if (arg === '--sections-dir') {
      opts.sectionsDir = requireValue(argv, ++i, arg);
    } else if (arg === '--output' || arg === '-o') {
      opts.output = requireValue(argv, ++i, arg);
    } else if (arg === '--no-toc') {
      opts.toc = false;
    } else if (arg === '--no-boundaries') {
      opts.boundaries = false;
    } else if (arg === '--exclude-usage-examples') {
      opts.excludeUsageExamples = true;
    } else {
      throw new Error(`Unknown option: ${arg}\n\n${usage}`);
    }
  }

  return opts;
}

function requireValue(argv, index, flag) {
  const value = argv[index];
  if (!value || value.startsWith('--')) {
    throw new Error(`Missing value for ${flag}`);
  }
  return value;
}

async function collectMarkdownFiles(rootDir, opts) {
  const rootAbs = path.resolve(rootDir);
  const files = [];

  async function walk(dirAbs) {
    const entries = await fs.readdir(dirAbs, { withFileTypes: true });
    entries.sort((a, b) => a.name.localeCompare(b.name, 'en'));

    for (const entry of entries) {
      const abs = path.join(dirAbs, entry.name);
      const rel = toPosix(path.relative(process.cwd(), abs));

      if (entry.isDirectory()) {
        if (opts.excludeUsageExamples && rel === 'sections/12-usage-examples') {
          continue;
        }
        await walk(abs);
      } else if (entry.isFile() && entry.name.endsWith('.md')) {
        files.push(abs);
      }
    }
  }

  await walk(rootAbs);
  return files.sort((a, b) => {
    const aRel = toPosix(path.relative(rootAbs, a));
    const bRel = toPosix(path.relative(rootAbs, b));
    return aRel.localeCompare(bRel, 'en');
  });
}

async function buildBundle(files, rootDir, opts) {
  const parts = [];
  const rootRel = toPosix(path.relative(process.cwd(), path.resolve(rootDir))) || '.';
  const generatedAt = new Date().toISOString();

  parts.push('<!--');
  parts.push('Generated by scripts/concat-sections.mjs');
  parts.push(`Source directory: ${rootRel}`);
  parts.push(`Generated at: ${generatedAt}`);
  parts.push('-->');
  parts.push('');
  parts.push('# Harness Spec Sections Bundle');
  parts.push('');
  parts.push(`Source directory: \`${rootRel}\``);
  parts.push('');

  if (opts.toc) {
    parts.push('## Included Files');
    parts.push('');
    for (const file of files) {
      parts.push(`- \`${toPosix(path.relative(process.cwd(), file))}\``);
    }
    parts.push('');
    parts.push('---');
    parts.push('');
  }

  for (const file of files) {
    const rel = toPosix(path.relative(process.cwd(), file));
    const content = await fs.readFile(file, 'utf8');

    if (opts.boundaries) {
      parts.push(`<!-- BEGIN ${rel} -->`);
      parts.push('');
    }

    parts.push(content.trimEnd());
    parts.push('');

    if (opts.boundaries) {
      parts.push(`<!-- END ${rel} -->`);
      parts.push('');
    }

    parts.push('---');
    parts.push('');
  }

  return `${parts.join('\n').trimEnd()}\n`;
}

function toPosix(value) {
  return value.split(path.sep).join('/');
}

async function main() {
  const opts = parseArgs(process.argv.slice(2));
  if (opts.help) {
    process.stdout.write(usage);
    return;
  }

  const files = await collectMarkdownFiles(opts.sectionsDir, opts);
  if (files.length === 0) {
    throw new Error(`No markdown files found under ${opts.sectionsDir}`);
  }

  const bundle = await buildBundle(files, opts.sectionsDir, opts);

  if (opts.output) {
    const outputAbs = path.resolve(opts.output);
    await fs.mkdir(path.dirname(outputAbs), { recursive: true });
    await fs.writeFile(outputAbs, bundle, 'utf8');
  } else {
    process.stdout.write(bundle);
  }
}

main().catch(error => {
  process.stderr.write(`${error.message}\n`);
  process.exitCode = 1;
});
